// Récupère les lignes du Google Sheet
const promptItems = $('Lecture des lignes du Sheets').all();

const newItems = [];

// Utilitaire: extraire domaines
function toDomain(url) {
  try {
    let hostname;
    try {
      hostname = new URL(url).hostname;
    } catch {
      const m = String(url).match(/^https?:\/\/([^/?#]+)/i);
      hostname = m ? m[1] : null;
    }
    return hostname ? hostname.replace(/^www\./, '') : null;
  } catch { return null; }
}

// Utilitaire: extraire toutes les URLs d’un contenu texte (Markdown + brut)
function extractUrlsFromText(txt) {
  if (!txt || typeof txt !== 'string') return [];
  const urls = [];

  // 1) Liens Markdown: [label](https://example.com/...)
  const mdRe = /\]\((https?:\/\/[^\s)]+)\)/g;
  let m;
  while ((m = mdRe.exec(txt)) !== null) urls.push(m[1]);

  // 2) URLs brutes dans le texte
  const rawRe = /https?:\/\/[^\s)]+/g;
  const raws = txt.match(rawRe) || [];
  for (const u of raws) urls.push(u);

  return urls;
}

for (let i = 0; i < items.length; i++) {
  try {
    const responseItem = items[i];
    const promptItem = promptItems[i];

    const currentPrompt = promptItem?.json?.Prompt || `PROMPT INTROUVABLE POUR L'ÉLÉMENT ${i + 1}`;
    const currentLangue = promptItem?.json?.Langue;

    const rd = responseItem?.json ?? {};
    let answerText = null;

    // --- Récupérer le texte de réponse (chat.completions)
    if (Array.isArray(rd.choices) && rd.choices[0]?.message) {
      const m = rd.choices[0].message;
      if (Array.isArray(m.content)) {
        const textPart = m.content.find(p => p?.type === 'text') ?? m.content[0];
        answerText = typeof textPart === 'string' ? textPart : (textPart?.text ?? null);
      } else {
        answerText = typeof m.content === 'string' ? m.content : null;
      }
    }

    // --- Collecte d’URLs: 1) objets 'url_citation' dans choices[*]
    const citationUrls = [];
    if (Array.isArray(rd.choices)) {
      for (const ch of rd.choices) {
        // Quelques proxys mettent { type:'url_citation', url_citation:{ url } }
        if (ch?.type === 'url_citation' && ch?.url_citation?.url) {
          citationUrls.push(ch.url_citation.url);
        }
        // Parfois directement { url_citation:{ url } } sans 'type'
        else if (ch?.url_citation?.url) {
          citationUrls.push(ch.url_citation.url);
        }
        // Rare: { annotations:[{url:...}] } au niveau du choice
        if (Array.isArray(ch?.annotations)) {
          for (const a of ch.annotations) if (a?.url) citationUrls.push(a.url);
        }
      }
    }

    // --- Collecte d’URLs: 2) liens présents dans le texte markdown
    const textUrls = extractUrlsFromText(answerText);

    // Fusion + dédoublonnage
    const uniqueUrls = [...new Set([...citationUrls, ...textUrls])];

    // Domaines uniques
    const uniqueDomains = [...new Set(uniqueUrls.map(toDomain).filter(Boolean))];

    // Si pas de texte, renvoyer quand même quelque chose de diagnostic
    if (!answerText) {
      newItems.push({
        json: {
          prompt: currentPrompt,
          langue: currentLangue,
          error: "Aucun texte de réponse détecté dans choices[0].message.content.",
          urls: uniqueUrls,
          domains: uniqueDomains,
          rawKeys: Object.keys(rd || {}),
        },
      });
      continue;
    }

    newItems.push({
      json: {
        prompt: currentPrompt,
        langue: currentLangue,
        answer: answerText,
        urls: uniqueUrls,
        domains: uniqueDomains,
      },
    });

  } catch (error) {
    newItems.push({
      json: {
        error: `Impossible de traiter l'élément ${i}: ${error.message || String(error)}`,
      },
    });
  }
}

return newItems;

// Prépare une "boîte" vide (un tableau) pour ranger tous nos résultats finaux.
const newItems = [];

// Démarre une boucle pour traiter chaque "item" (chaque ligne de données)
// qui arrive dans ce nœud, un par un.
for (const item of items) {
  // Ajoute une vérification de sécurité essentielle.
  // Si un item est vide ou mal formé (par exemple, il lui manque la clé "json",
  // ou la clé "candidates" de l'API), on ne peut pas le traiter.
  if (!item.json || !item.json.candidates || !item.json.candidates[0]) {
    // On affiche un avertissement dans le journal (logs) pour en garder une trace.
    console.warn("Ignorer un item mal formé ou vide.");
    // On arrête le traitement pour *cet* item et on passe directement au suivant dans la boucle.
    continue;
  }

  // On "essaie" (try) de faire le traitement principal.
  // C'est un filet de sécurité : si une erreur se produit à l'intérieur de ce bloc
  // (par exemple, la structure de la réponse a changé), le "catch" plus bas
  // l'interceptera sans faire planter tout le flux de travail.
  try {
    // --- 1. Données venant de notre source d'origine (ex: Google Sheet) ---
    // On récupère la colonne "Prompts" qui était attachée à cet item.
    // S'il ne la trouve pas (||), on met un texte d'erreur pour être au courant.
    const prompt = item.json.Prompt || 'PROMPT INTROUVABLE';
    // On fait pareil pour la colonne "Langue".
    const langue = item.json.Langue || 'LANGUE INTROUVABLE';

    // --- 2. Données venant de la réponse de l'API Gemini ---
    // On "plonge" dans la structure complexe de la réponse pour extraire le texte de la réponse principale.
    const answer = item.json.candidates[0].content.parts[0].text;

    // On fait de même pour trouver les "groundingChunks".
    // Ce sont les *sources* (citations, pages web) que l'IA a utilisées pour générer sa réponse.
    const groundingChunks = item.json.candidates[0].groundingMetadata.groundingChunks;

    // --- 3. Logique de traitement (le cœur du nœud) ---

    // CONDITION : Est-ce que l'IA a fourni des sources ?
    // (La liste "groundingChunks" existe-t-elle et n'est-elle pas vide ?)
    if (groundingChunks && groundingChunks.length > 0) {

      // OUI, des sources existent : On va créer une ligne *par source*.
      // S'il y a 3 sources, on créera 3 nouvelles lignes.

      // On démarre une *sous-boucle* : pour chaque source ("chunk") dans la liste des sources...
      for (const chunk of groundingChunks) {
        // ...on ajoute une nouvelle ligne à notre boîte de résultats "newItems".
        newItems.push({
          json: {
            prompt: prompt,     // Le prompt (sera le même pour chaque ligne éclatée)
            langue: langue,     // La langue (sera la même)
            answer: answer,     // La réponse de l'IA (sera la même)
            model: "Gemini-2.5-flash", // On note le modèle utilisé
            uri: chunk.web.uri, // L'URL (le lien) de la source spécifique
            title: chunk.web.title // Le titre de la page de la source
          }
        });
      }
    } else {
      // NON, il n'y a aucune source pour cette réponse.

      // On crée une *seule* ligne pour cette réponse, sans information de source.
      newItems.push({
        json: {
          prompt: prompt,
          langue: langue,
          answer: answer,
          model: "Gemini-2.5-flash",
          uri: "",   // On laisse le champ de l'URL vide
          title: "" // On laisse le champ du titre vide
        }
      });
    }
  } catch (error) {
    // C'est la deuxième partie de notre filet de sécurité (le "catch").
    // Si quelque chose a mal tourné DANS le "try" (par exemple, la structure
    // de 'candidates[0].content' a changé et le code n'a pas trouvé '.text')...
    // ...on enregistre l'erreur pour savoir ce qui s'est passé...
    console.error("Une erreur est survenue lors du traitement d'un item:", error);
    // ...et on continue la boucle principale. L'item en erreur est ignoré,
    // mais le flux de travail ne s'arrête pas.
  }
}

// Une fois que la boucle a traité TOUS les items...
// On renvoie la "boîte" `newItems` qui contient maintenant la liste complète
// de toutes nos nouvelles lignes (éclatées par source ou non).
return newItems;

const newItems = [];

for (const item of items) {
  try {
    const originalJson = item.json;
    const urls = JSON.parse(originalJson.URLs);

    const parentData = {
      date: originalJson.date,
      réponse: originalJson.réponse,
      modèle: originalJson.modèle,
      Prompt: originalJson.Prompt,
      langue: originalJson.langue
    };

    for (const url of urls) {
      let domaine = "EXTRACTION_ECHOUÉE";

      let cleanUrl = url.trim()
        .replace('?utm_source=openai', '')
        .replace('&utm_source=openai', '');

      try {
        let hostname = null;
        const matches = cleanUrl.match(/^https?:\/\/([^/?#]+)/i);

        if (matches && matches[1]) {
          hostname = matches[1];
        }

        if (hostname) {
          domaine = hostname.replace(/^www\./, '');
        }
      } catch (e) {
        console.error(`Erreur en traitant l'URL "${url}":`, e.message);
      }

      const newItem = {
        json: {
          ...parentData,
          URL: cleanUrl,
          Domaine: domaine
        }
      };

      newItems.push(newItem);
    }

  } catch (error) {
    console.error("Échec du traitement d'un item (ligne) :", error);
  }
}

return newItems;

