const inputItems = $input.all();

function asClaudeMessage(json) {
  // Handles:
  // 1) combined object: { Prompt, Langue, model, content, ... }
  // 2) raw Anthropic object: { model, content, ... }
  // 3) pasted array: [ { model, content, ... } ]
  // 4) wrapped HTTP output: { body: { ... } } or { data: { ... } }

  if (Array.isArray(json)) return json[0] ?? {};

  if (Array.isArray(json?.content)) return json;

  if (json?.body) return asClaudeMessage(json.body);
  if (json?.data) return asClaudeMessage(json.data);
  if (json?.response) return asClaudeMessage(json.response);

  return json ?? {};
}

function getPrompt(json) {
  return (
    json.Prompt ??
    json.prompt ??
    json.body?.Prompt ??
    json.body?.prompt ??
    json.data?.Prompt ??
    json.data?.prompt ??
    ""
  );
}

function getLanguage(json) {
  return (
    json.Langue ??
    json.langue ??
    json.language ??
    json.body?.Langue ??
    json.body?.langue ??
    json.body?.language ??
    json.data?.Langue ??
    json.data?.langue ??
    json.data?.language ??
    ""
  );
}

function pad(number, size = 2) {
  return String(number).padStart(size, "0");
}

function getParisNowIso() {
  const now = new Date();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Europe/Paris",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  }).formatToParts(now);

  const map = {};
  for (const part of parts) {
    map[part.type] = part.value;
  }

  // Europe/Paris is UTC+1 or UTC+2 depending on daylight saving time.
  const parisAsUtc = Date.UTC(
    Number(map.year),
    Number(map.month) - 1,
    Number(map.day),
    Number(map.hour),
    Number(map.minute),
    Number(map.second)
  );

  const offsetMinutes = Math.round((parisAsUtc - now.getTime()) / 60000);
  const sign = offsetMinutes >= 0 ? "+" : "-";
  const absOffset = Math.abs(offsetMinutes);
  const offsetHours = pad(Math.floor(absOffset / 60));
  const offsetMins = pad(absOffset % 60);

  return `${map.year}-${map.month}-${map.day}T${map.hour}:${map.minute}:${map.second}.${pad(now.getMilliseconds(), 3)}${sign}${offsetHours}:${offsetMins}`;
}

function getDate(json) {
  return (
    json.time ??
    json.timestamp ??
    json.date ??
    json.created_at ??
    json.startedAt ??
    json.body?.time ??
    json.body?.timestamp ??
    json.body?.date ??
    json.body?.created_at ??
    getParisNowIso()
  );
}

function getDomain(url) {
  if (!url) return "";

  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return url
      .replace(/^https?:\/\//, "")
      .replace(/^www\./, "")
      .split("/")[0]
      .split("?")[0]
      .split("#")[0];
  }
}

function cleanAnswerText(text) {
  return text
    .replace(/\r?\n+/g, " ")   // remove \n and line breaks
    .replace(/---+/g, " ")     // remove Markdown separators
    .replace(/\s+/g, " ")      // collapse repeated spaces
    .trim();
}

function extractText(content) {
  return cleanAnswerText(
    content
      .filter(block => block?.type === "text")
      .map(block => block.text ?? "")
      .join("")
  );
}

function extractUrls(content) {
  const urls = [];

  for (const block of content) {
    if (block?.type !== "web_search_tool_result") continue;

    const results = block.content ?? [];

    for (const result of results) {
      if (result?.type === "web_search_result" && result.url) {
        urls.push(result.url);
      }
    }
  }

  return [...new Set(urls)];
}

const output = [];

for (const item of inputItems) {
  const original = item.json;
  const msg = asClaudeMessage(original);
  const content = msg.content ?? [];

  const responseText = extractText(content);
  const urls = extractUrls(content);

  const baseRow = {
    "Date": getDate(original),
    "Réponse": responseText,
    "Modèle": msg.model ?? original.model ?? "",
    "Prompt": getPrompt(original),
    "Langue": getLanguage(original),
  };

  // Optional: preserve the original row number from Google Sheets / Airtable
  if (original.row_number !== undefined) {
    baseRow.row_number = original.row_number;
  }

  // One row per source URL
  if (urls.length > 0) {
    for (const url of urls) {
      output.push({
        json: {
          ...baseRow,
          "URL": url,
          "Domaine": getDomain(url),
        },
      });
    }
  } else {
    output.push({
      json: {
        ...baseRow,
        "URL": "",
        "Domaine": "",
      },
    });
  }
}

return output;

// n8n Code node (Run Once for All Items)

const inputItems = $input.all();
const out = [];

function toDomain(url) {
  try {
    return new URL(url).hostname.replace(/^www\./i, '');
  } catch (e) {
    // Fallback for odd / malformed strings
    return String(url)
      .replace(/^https?:\/\//i, '')
      .split('/')[0]
      .replace(/^www\./i, '');
  }
}

for (const item of inputItems) {
  const data = item.json ?? {};
  const prompt = data.Prompt ?? data.prompt ?? '';

  // Collect ALL assistant output_text blocks (just in case there are multiple)
  const outputTexts = [];
  const urls = [];

  const outputArr = Array.isArray(data.output) ? data.output : [];
  for (const block of outputArr) {
    if (block?.type !== 'message' || block?.role !== 'assistant') continue;

    const contentArr = Array.isArray(block.content) ? block.content : [];
    for (const c of contentArr) {
      if (c?.type !== 'output_text') continue;

      if (typeof c.text === 'string') outputTexts.push(c.text);

      // Preferred: use structured annotations (url_citation)
      const anns = Array.isArray(c.annotations) ? c.annotations : [];
      for (const ann of anns) {
        if (ann?.type === 'url_citation' && ann.url) {
          urls.push(ann.url);
        }
      }
    }
  }

  const output_text = outputTexts.join('\n\n');

  // Fallbacks if annotations weren’t present
  if (urls.length === 0 && Array.isArray(data.citations)) {
    urls.push(...data.citations);
  }
  if (urls.length === 0 && output_text) {
    // Pull URLs from markdown links like [[1]](https://...)
    const re = /\((https?:\/\/[^\s)]+)\)/g;
    let m;
    while ((m = re.exec(output_text)) !== null) urls.push(m[1]);
  }

  // One item per UNIQUE url
  const uniqueUrls = [...new Set(urls)];

  for (const url of uniqueUrls) {
    out.push({
      json: {
        prompt,
        output_text,
        url,
        domain: toDomain(url),
      },
    });
  }
}

return out;
